import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;

import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        // Simulating user input (e.g., from a form submission)
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by sanitizing and escaping it before including in the HTML response
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Writing sanitized input to an HTML file
        try (PrintWriter out = new PrintWriter(new FileWriter("output.html"))) {
            out.println("<html>");
            out.println("<body>");
            out.println("<h1>Hello, " + sanitizedInput + "</h1>");
            out.println("</body>");
            out.println("</html>");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
